// ============================================================
// TESTWORKFLOW – KEIN PRODUKTIONSBETRIEB
// Zweck: Bulk-Import-Pipeline lokal testen ohne Apify.
// Hinweis: Kleinanzeigen blockt direkte HTTP-Requests
// nach wenigen Aufrufen (Cloudflare). Dieser Workflow
// fällt dann auf Mock-Daten zurück.
// ============================================================

const testKeyword = 'Solarzaun';
const html = String($input.first().json.data || $input.first().json || '');

const listings = [];
const seen = new Set();

// Versuche echte adIds aus HTML zu extrahieren (funktioniert nur ohne 403)
if (html.length > 1000 && html.includes('data-adid')) {
  let pos = 0;
  while (pos < html.length && listings.length < 10) {
    const idx = html.indexOf('data-adid="', pos);
    if (idx === -1) break;

    const start = idx + 11;
    const end = html.indexOf('"', start);
    if (end === -1 || end - start > 15) { pos = idx + 1; continue; }

    const adId = html.substring(start, end);
    pos = end + 1;

    if (!adId || seen.has(adId)) continue;
    seen.add(adId);

    // URL aus nahem HTML extrahieren
    const near = html.substring(Math.max(0, idx - 600), Math.min(html.length, idx + 600));
    let url = null;
    const hrefIdx = near.indexOf('href="/s-anzeige/');
    if (hrefIdx !== -1) {
      const hrefStart = hrefIdx + 6;
      const hrefEnd = near.indexOf('"', hrefStart);
      if (hrefEnd !== -1) {
        url = 'https://www.kleinanzeigen.de' + near.substring(hrefStart, hrefEnd);
      }
    }

    // Titel aus nahem HTML extrahieren
    let title = 'Kleinanzeige ' + adId;
    const h3Idx = near.indexOf('<h2 class="');
    if (h3Idx !== -1) {
      const closeIdx = near.indexOf('</h2>', h3Idx);
      if (closeIdx !== -1) {
        const raw = near.substring(h3Idx, closeIdx);
        const gt = raw.lastIndexOf('>');
        if (gt !== -1) {
          const extracted = raw.substring(gt + 1).trim();
          if (extracted.length > 3) title = extracted;
        }
      }
    }

    listings.push({
      adId,
      title,
      price: null,
      description: null,
      location: null,
      plz: null,
      date: null,
      url: url || ('https://www.kleinanzeigen.de/s-anzeige/anzeige/' + adId + '-168-1234'),
      image: null,
      shipping: null,
    });
  }
}

// Fallback: Mock-Daten wenn kein echtes Scraping möglich
if (listings.length === 0) {
  const now = new Date().toISOString();
  listings.push(
    {
      adId: '9000000001',
      title: '[TESTDATEN] Solarzaun 10m – nach Test löschen',
      price: '1.200 EUR VB',
      description: 'TESTDATEN – automatisch erzeugt. Bitte nach Pipeline-Test löschen.',
      location: 'München',
      plz: '80331',
      date: now,
      url: 'https://www.kleinanzeigen.de/s-anzeige/test-solarzaun/9000000001-168-1234',
      image: null,
      shipping: 'Abholung',
    },
    {
      adId: '9000000002',
      title: '[TESTDATEN] PV-Zaun bifazial 8m – nach Test löschen',
      price: '950 EUR',
      description: 'TESTDATEN – automatisch erzeugt. Bitte nach Pipeline-Test löschen.',
      location: 'Hamburg',
      plz: '20099',
      date: now,
      url: 'https://www.kleinanzeigen.de/s-anzeige/test-pv-zaun/9000000002-168-5678',
      image: null,
      shipping: null,
    },
    {
      adId: '9000000003',
      title: '[TESTDATEN] Solarzaun Komplettsystem – nach Test löschen',
      price: '2.500 EUR VB',
      description: 'TESTDATEN – automatisch erzeugt. Bitte nach Pipeline-Test löschen.',
      location: 'Berlin',
      plz: '10115',
      date: now,
      url: 'https://www.kleinanzeigen.de/s-anzeige/test-solarzaun-komplett/9000000003-168-9012',
      image: null,
      shipping: 'Versand möglich',
    }
  );
}

return [{
  json: {
    source: 'kleinanzeigen',
    keyword: testKeyword,
    usedMockData: listings[0] && listings[0].adId.startsWith('900'),
    listingCount: listings.length,
    listings,
  }
}];
